protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing documents and direct SQL queries use "Discriminator", so keep the old name.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id values from "EntityType|Key" (e.g. "Product|123") to just "Key".
        // Existing 500K documents use the compound format, so preserve it.
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // Removed HasIndex — EF Core 9 Cosmos provider throws at startup for HasIndex calls.
    // Manage indexing via the Cosmos DB indexing policy (Azure Portal / Bicep / Terraform).
}

